import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Plus, Minus, Trash2, ShoppingBag } from 'lucide-react';
import { CartItem } from '../types';

interface CartOverlayProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onUpdateQuantity: (id: string, delta: number) => void;
  onRemove: (id: string) => void;
}

export const CartOverlay: React.FC<CartOverlayProps> = ({ 
  isOpen, 
  onClose, 
  items, 
  onUpdateQuantity, 
  onRemove 
}) => {
  const subtotal = items.reduce((acc, item) => acc + item.price * item.quantity, 0);

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Backdrop */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-black/40 backdrop-blur-sm z-[100]"
          />

          {/* Sidebar */}
          <motion.div
            initial={{ x: '100%' }}
            animate={{ x: 0 }}
            exit={{ x: '100%' }}
            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
            className="fixed top-0 right-0 h-full w-full md:w-[450px] bg-white z-[101] shadow-2xl flex flex-col"
          >
            <div className="p-8 flex justify-between items-center border-b">
              <div>
                <h2 className="text-3xl font-black tracking-tight">Your Cart</h2>
                <p className="text-gray-500 font-bold uppercase tracking-widest text-[10px]">Taste Premium Dining</p>
              </div>
              <button 
                onClick={onClose}
                className="p-3 bg-gray-100 rounded-2xl hover:bg-gray-200 transition-colors"
              >
                <X size={24} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              {items.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-center space-y-4 opacity-50">
                  <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center">
                    <ShoppingBag size={32} />
                  </div>
                  <p className="font-bold text-gray-400 uppercase tracking-widest">Cart is empty</p>
                </div>
              ) : (
                items.map((item) => (
                  <motion.div 
                    layout
                    key={item.id} 
                    className="flex gap-4 items-center"
                  >
                    <div className="w-24 h-24 rounded-3xl overflow-hidden shadow-lg shrink-0">
                      <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <h4 className="font-bold text-lg truncate">{item.name}</h4>
                      <p className="text-orange-500 font-black mb-2">${item.price.toFixed(2)}</p>

                      <div className="flex items-center gap-4">
                        <div className="flex items-center bg-gray-100 rounded-xl p-1">
                          <button 
                            onClick={() => onUpdateQuantity(item.id, -1)}
                            className="p-1 hover:bg-white rounded-lg transition-colors"
                          >
                            <Minus size={16} />
                          </button>
                          <span className="w-8 text-center font-black text-sm">{item.quantity}</span>
                          <button 
                            onClick={() => onUpdateQuantity(item.id, 1)}
                            className="p-1 hover:bg-white rounded-lg transition-colors"
                          >
                            <Plus size={16} />
                          </button>
                        </div>
                        <button 
                          onClick={() => onRemove(item.id)}
                          className="text-gray-400 hover:text-red-500 transition-colors"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    </div>
                  </motion.div>
                ))
              )}
            </div>

            <div className="p-8 bg-gray-50 border-t space-y-6">
              <div className="flex justify-between items-center text-xl">
                <span className="font-bold text-gray-500">Subtotal</span>
                <span className="font-black">${subtotal.toFixed(2)}</span>
              </div>
              <button 
                disabled={items.length === 0}
                className="w-full bg-black text-white py-5 rounded-[24px] font-black text-lg shadow-2xl hover:bg-orange-500 transition-all disabled:opacity-50 disabled:bg-gray-400"
              >
                Checkout Now
              </button>
              <p className="text-center text-[10px] text-gray-400 uppercase tracking-widest font-bold">
                Taxes and shipping calculated at checkout
              </p>
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ShoppingCart, Menu, ArrowRight, Phone, Mail, MapPin, Apple, Play, X, ChevronRight, Instagram, Twitter, Facebook } from 'lucide-react';
import { CustomCursor } from './components/CustomCursor';
import { FloatingDecorations } from './components/FloatingDecorations';
import { FoodCard } from './components/FoodCard';
import { Gallery } from './components/Gallery';
import { AboutSection } from './components/AboutSection';
import { ReservationForm } from './components/ReservationForm';
import { CartOverlay } from './components/CartOverlay';
import { CATEGORIES, FOOD_ITEMS, NAV_LINKS } from './constants';
import { FoodItem, CartItem } from './types';

const App: React.FC = () => {
  const [activePage, setActivePage] = useState('home');
  const [activeCategory, setActiveCategory] = useState('all');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);

  // Scroll to top on page change
  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [activePage]);

  const cartCount = cartItems.reduce((acc, item) => acc + item.quantity, 0);

  const handleAddToCart = (item: FoodItem) => {
    setCartItems(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const updateQuantity = (id: string, delta: number) => {
    setCartItems(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCartItems(prev => prev.filter(item => item.id !== id));
  };

  const filteredItems = useMemo(() => {
    if (activeCategory === 'all') return FOOD_ITEMS;
    return FOOD_ITEMS.filter(item => item.category === activeCategory);
  }, [activeCategory]);

  const pageTransition = {
    initial: { opacity: 0, y: 20 },
    animate: { opacity: 1, y: 0 },
    exit: { opacity: 0, y: -20 },
    transition: { duration: 0.5, ease: [0.22, 1, 0.36, 1] as any }
  };

  const handleNavigate = (href: string) => {
    const page = href.replace('#', '');
    setActivePage(page);
    setIsMobileMenuOpen(false);
  };

  const menuContainerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1,
        delayChildren: 0.2
      }
    },
    exit: {
      opacity: 0,
      transition: {
        staggerChildren: 0.05,
        staggerDirection: -1
      }
    }
  };

  const menuItemVariants = {
    hidden: { opacity: 0, x: 50, rotate: 5 },
    visible: { 
      opacity: 1, 
      x: 0, 
      rotate: 0,
      transition: { type: 'spring' as const, damping: 20, stiffness: 100 }
    },
    exit: { opacity: 0, x: -20, transition: { duration: 0.2 } }
  };

  return (
    <div className="min-h-screen relative text-gray-900 overflow-x-hidden bg-[#f8f4f1] scroll-smooth">
      <CustomCursor />
      <FloatingDecorations />

      <CartOverlay 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)}
        items={cartItems}
        onUpdateQuantity={updateQuantity}
        onRemove={removeFromCart}
      />

      {/* Navigation */}
      <nav className="fixed top-0 left-0 right-0 z-[60] flex justify-between items-center px-6 md:px-12 py-6 bg-white/10 backdrop-blur-md border-b border-white/20">
        <motion.div 
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          className="flex flex-col cursor-pointer"
          onClick={() => setActivePage('home')}
        >
          <span className="text-2xl font-black tracking-tighter">Taste</span>
          <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-gray-400">Restaurant & BBQ</span>
        </motion.div>

        <div className="hidden md:flex items-center gap-10">
          {NAV_LINKS.map((link) => (
            <button 
              key={link.label} 
              onClick={() => handleNavigate(link.href)}
              className={`font-bold text-xs uppercase tracking-[0.2em] transition-all hover:text-orange-500 ${
                activePage === link.href.replace('#', '') ? 'text-orange-600' : 'text-gray-600'
              }`}
            >
              {link.label}
            </button>
          ))}
        </div>

        <div className="flex items-center gap-4">
          <motion.button 
            whileHover={{ scale: 1.1 }}
            whileTap={{ scale: 0.9 }}
            onClick={() => setIsCartOpen(true)}
            className="relative p-3 bg-black text-white rounded-2xl shadow-xl hover:bg-orange-500 transition-colors"
          >
            <ShoppingCart size={20} />
            {cartCount > 0 && (
              <motion.span 
                initial={{ scale: 0 }}
                animate={{ scale: 1 }}
                key={cartCount}
                className="absolute -top-1 -right-1 w-5 h-5 bg-orange-500 text-[10px] font-bold rounded-full flex items-center justify-center ring-2 ring-white"
              >
                {cartCount}
              </motion.span>
            )}
          </motion.button>
          <button 
            onClick={() => setIsMobileMenuOpen(true)}
            className="md:hidden p-3 bg-white/80 backdrop-blur-md rounded-2xl border border-white/50 hover:bg-white transition-colors"
          >
            <Menu size={20} />
          </button>
        </div>
      </nav>

      {/* Enhanced Mobile Menu Overlay */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/95 backdrop-blur-3xl z-[100] flex flex-col overflow-hidden"
          >
            <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-orange-500/10 blur-[150px] rounded-full translate-x-1/3 -translate-y-1/3 pointer-events-none" />

            <div className="relative z-10 p-8 h-full flex flex-col">
              <div className="flex justify-between items-center mb-16">
                <div className="flex flex-col text-white">
                  <span className="text-2xl font-black tracking-tighter">Taste</span>
                  <span className="text-[8px] uppercase tracking-[0.2em] font-bold text-gray-500">Premium Dining</span>
                </div>
                <motion.button 
                  initial={{ rotate: -90, opacity: 0 }}
                  animate={{ rotate: 0, opacity: 1 }}
                  whileTap={{ scale: 0.9 }}
                  onClick={() => setIsMobileMenuOpen(false)}
                  className="p-4 text-white bg-white/10 rounded-full hover:bg-white/20 transition-colors"
                >
                  <X size={28} />
                </motion.button>
              </div>

              <motion.div 
                variants={menuContainerVariants}
                initial="hidden"
                animate="visible"
                exit="exit"
